proof fn phi_1_leads_to_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>, i: nat)
    requires
        p.leads_to(q).satisfied_by(ex),
    ensures
        p.implies(eventually(q)).satisfied_by(ex.suffix(i)),
{
    leads_to_unfold::<int>(ex, p, q);
}

proof fn phi_2_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_4_eventually_proved_by_witness_intensional_bridge(ex: Execution<int>, p: TempPred<int>, witness_idx: nat)
    requires
        p.satisfied_by(ex.suffix(witness_idx)),
    ensures
        eventually(p).satisfied_by(ex),
{
    eventually_proved_by_witness::<int>(ex, p, witness_idx);
}

proof fn phi_5_or_framing_false_spec(p: TempPred<int>, q: TempPred<int>, r: TempPred<int>)
    requires
        TempPred::<int>::new(|ex: Execution<int>| false).entails(p.leads_to(q)),
    ensures
        TempPred::<int>::new(|ex: Execution<int>| false).entails(p.or(r).leads_to(q.or(r))),
{
    leads_to_framed_by_or::<int>(TempPred::new(|ex: Execution<int>| false), p, q, r);
}
